#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &x){if(x>9)print(x/10);putchar(x%10+'0');}
inline int qpow(int a,int b,int Mod)
{
	int res=1;while(b)
	{
		if(b&1)res=1ll*res*a%Mod;
		a=1ll*a*a%Mod;b=b>>1;
	}
	return res;
}
namespace Sub1
{
	inline void Solve()
	{
		int n=read();if(n==1)return puts("2 1"),void();if(n&1)return puts("0"),void();
		putchar('2');rep(1,n,i)putchar(' '),print(i&1?n-i+1:i-1);putchar('\n');return;
	}
	inline void mian(){int T=read();while(T--)Solve();}
}
namespace Sub2
{
	inline bool isprime(const int &p){for(int j=2;j*j<=p;++j)if(p%j==0)return false;return true;}
	inline void Solve()
	{
		int n=read();if(n==1)return puts("2 1"),void();
		if(n==4)return puts("2 1 3 2 4"),void();if(!isprime(n))return puts("0"),void();
		putchar('2');int sum=1,x=1;for(int i=1;i<n;++i)
		{
			putchar(' ');print(x);
			x=1ll*qpow(sum,n-2,n)*(i+1)%n;
			sum=1ll*sum*x%n;
		}
		putchar(' ');print(n);putchar('\n');
	}
	inline void mian(){int T=read();while(T--)Solve();}
}
int main(){read()==1?Sub1::mian():Sub2::mian();return 0;}
